import { Router } from 'express';
import { db } from '../db';
import { readLocalUsers, writeLocalUsers } from '../localFallback';

const router = Router();

// In-memory rate limiter: max 10 attempts per IP per minute
const attempts = new Map<string, { count: number; resetAt: number }>();

function checkRateLimit(ip: string): boolean {
  const now = Date.now();
  const entry = attempts.get(ip);
  if (!entry || entry.resetAt < now) {
    attempts.set(ip, { count: 1, resetAt: now + 60_000 });
    return true;
  }
  if (entry.count >= 10) return false;
  entry.count++;
  return true;
}

// POST /api/auth/login
router.post('/login', async (req, res) => {
  const ip = req.ip || req.socket.remoteAddress || 'unknown';
  if (!checkRateLimit(ip)) {
    return res.status(429).json({ success: false, error: 'Слишком много попыток. Подождите минуту.' });
  }

  const { name, pin } = req.body;
  if (!pin) {
    return res.status(400).json({ success: false, error: 'ПИН-код обязателен' });
  }

  let matchedUser: any = null;

  if (db.pool && db.isConnected) {
    try {
      const query = name
        ? 'SELECT * FROM marketing_users WHERE name = $1 AND pin = $2'
        : 'SELECT * FROM marketing_users WHERE pin = $1';
      const params = name ? [name, pin] : [pin];
      const result = await db.pool.query(query, params);

      if (result.rows.length > 0) {
        const row = result.rows[0];
        matchedUser = {
          name: row.name, role: row.role, pin: row.pin,
          department: row.department, bio: row.bio,
          avatarColor: row.avatar_color, status: 'online', lastActive: 'В сети',
        };
        await db.pool.query(
          'UPDATE marketing_users SET status = $1, last_active = $2, last_seen_at = NOW() WHERE name = $3',
          ['online', 'В сети', row.name]
        );
      }
    } catch (err) {
      console.error('[Auth] DB login error:', err);
    }
  }

  if (!matchedUser) {
    const users = readLocalUsers();
    matchedUser = name
      ? users.find((u: any) => u.name === name && u.pin === pin)
      : users.find((u: any) => u.pin === pin);

    if (matchedUser) {
      const idx = users.findIndex((u: any) => u.name === matchedUser.name);
      if (idx >= 0) {
        users[idx].status = 'online';
        users[idx].lastActive = 'В сети';
        users[idx].lastSeenAt = new Date().toISOString();
        writeLocalUsers(users);
      }
    }
  }

  if (matchedUser) {
    return res.json({ success: true, user: matchedUser });
  }
  res.status(401).json({ success: false, error: 'Неверный ПИН-код' });
});

// POST /api/auth/logout
router.post('/logout', async (req, res) => {
  const { name } = req.body;
  if (!name) return res.json({ success: true });

  if (db.pool && db.isConnected) {
    try {
      // Set last_seen_at far in the past so status immediately reads as offline
      await db.pool.query(
        `UPDATE marketing_users
         SET status = 'offline', last_active = $1, last_seen_at = NOW() - interval '1 year'
         WHERE name = $2`,
        [new Date().toLocaleTimeString('ru-RU', { hour: '2-digit', minute: '2-digit' }) + ' назад', name]
      );
    } catch (err) {
      console.error('[Auth] DB logout error:', err);
    }
  } else {
    const users = readLocalUsers();
    const idx = users.findIndex((u: any) => u.name === name);
    if (idx >= 0) {
      users[idx].status = 'offline';
      users[idx].lastSeenAt = null;
      writeLocalUsers(users);
    }
  }
  res.json({ success: true });
});

// POST /api/auth/heartbeat  — called every ~60s by the client while active
router.post('/heartbeat', async (req, res) => {
  const { name } = req.body;
  if (!name) return res.status(400).json({ success: false });

  if (db.pool && db.isConnected) {
    try {
      await db.pool.query(
        `UPDATE marketing_users SET last_seen_at = NOW(), status = 'online', last_active = 'В сети' WHERE name = $1`,
        [name]
      );
    } catch (err) {
      console.error('[Auth] Heartbeat error:', err);
    }
  } else {
    const users = readLocalUsers();
    const idx = users.findIndex((u: any) => u.name === name);
    if (idx >= 0) {
      users[idx].status = 'online';
      users[idx].lastSeenAt = new Date().toISOString();
      writeLocalUsers(users);
    }
  }
  res.json({ success: true });
});

export default router;

import { Router } from 'express';
import { db } from '../db';
import { readLocalUsers, writeLocalUsers } from '../localFallback';

const router = Router();

// Online threshold: 3 minutes (heartbeat every 60s, so 3 missed beats = offline)
const ONLINE_THRESHOLD_MS = 3 * 60 * 1000;

function deriveStatus(lastSeenAt: Date | null): 'online' | 'offline' {
  if (!lastSeenAt) return 'offline';
  return (Date.now() - lastSeenAt.getTime()) < ONLINE_THRESHOLD_MS ? 'online' : 'offline';
}

function formatLastSeen(lastSeenAt: Date | null): string {
  if (!lastSeenAt) return 'Не в сети';
  const diffMs = Date.now() - lastSeenAt.getTime();
  if (diffMs < 0) return 'Не в сети';
  if (diffMs < ONLINE_THRESHOLD_MS) return 'В сети';
  const diffMin = Math.floor(diffMs / 60_000);
  if (diffMin < 60) return `${diffMin} мин назад`;
  const diffH = Math.floor(diffMin / 60);
  if (diffH < 24) return `${diffH} ч назад`;
  const diffD = Math.floor(diffH / 24);
  return `${diffD} д назад`;
}

function mapRow(row: any) {
  const lastSeenAt: Date | null = row.last_seen_at ? new Date(row.last_seen_at) : null;
  const status = deriveStatus(lastSeenAt);
  return {
    name: row.name,
    role: row.role,
    pin: row.pin,
    department: row.department,
    bio: row.bio,
    avatarColor: row.avatar_color,
    status,
    lastActive: formatLastSeen(lastSeenAt),
  };
}

// GET /api/users
router.get('/', async (_req, res) => {
  if (db.pool && db.isConnected) {
    try {
      const result = await db.pool.query('SELECT * FROM marketing_users ORDER BY name ASC');
      return res.json(result.rows.map(mapRow));
    } catch (err: any) {
      return res.status(500).json({ error: err.message });
    }
  }
  res.json(readLocalUsers());
});

// POST /api/users  (create or upsert)
router.post('/', async (req, res) => {
  const { name, role, pin, department, bio, avatarColor } = req.body;
  if (!name || !role || !pin) {
    return res.status(400).json({ error: 'ФИО, роль и ПИН-код обязательны' });
  }
  const dept = department || (role === 'admin' ? 'Администрация' : 'Отдел продаж');
  const color = avatarColor || 'from-indigo-500 to-purple-600';

  if (db.pool && db.isConnected) {
    try {
      await db.pool.query(`
        INSERT INTO marketing_users (name, role, pin, department, bio, avatar_color, status, last_active)
        VALUES ($1, $2, $3, $4, $5, $6, 'offline', 'Не в сети')
        ON CONFLICT (name) DO UPDATE SET
          role = EXCLUDED.role, pin = EXCLUDED.pin, department = EXCLUDED.department,
          bio = EXCLUDED.bio, avatar_color = EXCLUDED.avatar_color
      `, [name, role, pin, dept, bio || '', color]);
      return res.json({ success: true, name });
    } catch (err: any) {
      return res.status(500).json({ error: 'Database write error: ' + err.message });
    }
  }

  const users = readLocalUsers();
  const idx = users.findIndex((u: any) => u.name === name);
  const user = { name, role, pin, department: dept, bio: bio || '', avatarColor: color, status: 'offline', lastActive: 'Не в сети' };
  if (idx >= 0) users[idx] = { ...users[idx], ...user };
  else users.push(user);
  writeLocalUsers(users);
