  if (diffMs < 0) return 'Не в сети';
  if (diffMs < ONLINE_THRESHOLD_MS) return 'В сети';
  const diffMin = Math.floor(diffMs / 60_000);
  if (diffMin < 60) return `${diffMin} мин назад`;
