import { Router } from 'express';
import { db } from '../db';

const router = Router();

// ── helpers ────────────────────────────────────────────────────────────────

function sessionView(row: any) {
  return {
    id:             row.id,
    managerName:    row.manager_name,
    startedAt:      row.started_at,
    endedAt:        row.ended_at || null,
    breakStartedAt: row.break_started_at || null,
    totalBreakSecs: row.total_break_secs,
  };
}

// ── GET /api/shifts/active?name=X ──────────────────────────────────────────
router.get('/active', async (req, res) => {
  const { name } = req.query;
  if (!name || typeof name !== 'string')
    return res.status(400).json({ error: 'name required' });

  if (!db.pool || !db.isConnected)
    return res.json({ active: false, session: null });

  try {
    const r = await db.pool.query(
      `SELECT * FROM work_sessions
       WHERE manager_name = $1 AND ended_at IS NULL
       ORDER BY started_at DESC LIMIT 1`,
      [name]
    );
    if (r.rows.length === 0) return res.json({ active: false, session: null });
    return res.json({ active: true, session: sessionView(r.rows[0]) });
  } catch (err: any) {
    return res.status(500).json({ error: err.message });
  }
});

// ── POST /api/shifts/start ─────────────────────────────────────────────────
router.post('/start', async (req, res) => {
  const { name } = req.body;
  if (!name) return res.status(400).json({ error: 'name required' });

  if (!db.pool || !db.isConnected)
    return res.json({ success: true, session: null, fallback: true });

  try {
    // Close any stale open sessions (safety guard)
    await db.pool.query(
      `UPDATE work_sessions SET ended_at = NOW()
       WHERE manager_name = $1 AND ended_at IS NULL`,
      [name]
    );
    const r = await db.pool.query(
      `INSERT INTO work_sessions (manager_name, started_at)
       VALUES ($1, NOW()) RETURNING *`,
      [name]
    );
    return res.json({ success: true, session: sessionView(r.rows[0]) });
  } catch (err: any) {
    return res.status(500).json({ error: err.message });
  }
});

// ── POST /api/shifts/end ───────────────────────────────────────────────────
router.post('/end', async (req, res) => {
  const { name } = req.body;
  if (!name) return res.status(400).json({ error: 'name required' });

  if (!db.pool || !db.isConnected)
    return res.json({ success: true, workedSeconds: 0, fallback: true });

  try {
    // If currently on break, close it first
    await db.pool.query(
      `UPDATE work_sessions
       SET total_break_secs = total_break_secs +
             EXTRACT(EPOCH FROM (NOW() - break_started_at))::INT,
           break_started_at = NULL
       WHERE manager_name = $1 AND ended_at IS NULL
         AND break_started_at IS NOT NULL`,
      [name]
    );
    const r = await db.pool.query(
      `UPDATE work_sessions
       SET ended_at = NOW()
       WHERE manager_name = $1 AND ended_at IS NULL
       RETURNING EXTRACT(EPOCH FROM (ended_at - started_at))::INT - total_break_secs AS worked_secs`,
      [name]
    );
    const workedSeconds = r.rows[0]?.worked_secs ?? 0;
    return res.json({ success: true, workedSeconds: Math.max(0, workedSeconds) });
  } catch (err: any) {
    return res.status(500).json({ error: err.message });
  }
});

// ── POST /api/shifts/break/start ───────────────────────────────────────────
router.post('/break/start', async (req, res) => {
  const { name } = req.body;
  if (!name) return res.status(400).json({ error: 'name required' });

  if (!db.pool || !db.isConnected)
    return res.json({ success: true, fallback: true });

  try {
    await db.pool.query(
      `UPDATE work_sessions
       SET break_started_at = NOW()
       WHERE manager_name = $1 AND ended_at IS NULL
         AND break_started_at IS NULL`,
      [name]
    );
    return res.json({ success: true });
  } catch (err: any) {
    return res.status(500).json({ error: err.message });
  }
});

// ── POST /api/shifts/break/end ─────────────────────────────────────────────
router.post('/break/end', async (req, res) => {
  const { name } = req.body;
  if (!name) return res.status(400).json({ error: 'name required' });

  if (!db.pool || !db.isConnected)
    return res.json({ success: true, fallback: true });

  try {
    await db.pool.query(
      `UPDATE work_sessions
       SET total_break_secs = total_break_secs +
             EXTRACT(EPOCH FROM (NOW() - break_started_at))::INT,
           break_started_at = NULL
       WHERE manager_name = $1 AND ended_at IS NULL
         AND break_started_at IS NOT NULL`,
      [name]
    );
    return res.json({ success: true });
  } catch (err: any) {
    return res.status(500).json({ error: err.message });
  }
});

// ── GET /api/shifts/monthly?name=X&year=YYYY&month=MM ─────────────────────
// Returns total WORKED seconds (excluding breaks) for a given month
router.get('/monthly', async (req, res) => {
  const { name, year, month } = req.query;
  if (!name || !year || !month)
    return res.status(400).json({ error: 'name, year, month required' });

  if (!db.pool || !db.isConnected)
    return res.json({ totalSeconds: 0 });

  try {
    const r = await db.pool.query(
      `SELECT COALESCE(SUM(
         EXTRACT(EPOCH FROM (COALESCE(ended_at, NOW()) - started_at))::INT
         - total_break_secs
         - CASE WHEN break_started_at IS NOT NULL
                THEN EXTRACT(EPOCH FROM (NOW() - break_started_at))::INT
                ELSE 0 END
       ), 0) AS total_secs
       FROM work_sessions
       WHERE manager_name = $1
         AND EXTRACT(YEAR  FROM started_at AT TIME ZONE 'Europe/Moscow') = $2
         AND EXTRACT(MONTH FROM started_at AT TIME ZONE 'Europe/Moscow') = $3`,
      [name, parseInt(year as string), parseInt(month as string)]
    );
    return res.json({ totalSeconds: Math.max(0, parseInt(r.rows[0].total_secs)) });
  } catch (err: any) {
    return res.status(500).json({ error: err.message });
  }
});

// ── GET /api/shifts/monthly-all?year=YYYY&month=MM ────────────────────────
// Returns { managerName: totalSeconds } for all managers this month
router.get('/monthly-all', async (req, res) => {
  const { year, month } = req.query;
  if (!year || !month)
    return res.status(400).json({ error: 'year, month required' });

  if (!db.pool || !db.isConnected)
    return res.json({});

  try {
    const r = await db.pool.query(
      `SELECT manager_name,
         COALESCE(SUM(
           EXTRACT(EPOCH FROM (COALESCE(ended_at, NOW()) - started_at))::INT
           - total_break_secs
           - CASE WHEN break_started_at IS NOT NULL
                  THEN EXTRACT(EPOCH FROM (NOW() - break_started_at))::INT
                  ELSE 0 END
         ), 0) AS total_secs
       FROM work_sessions
       WHERE EXTRACT(YEAR  FROM started_at AT TIME ZONE 'Europe/Moscow') = $1
         AND EXTRACT(MONTH FROM started_at AT TIME ZONE 'Europe/Moscow') = $2
       GROUP BY manager_name`,
      [parseInt(year as string), parseInt(month as string)]
    );
    const result: Record<string, number> = {};
    for (const row of r.rows) {
      result[row.manager_name] = Math.max(0, parseInt(row.total_secs));
    }
    return res.json(result);
  } catch (err: any) {
    return res.status(500).json({ error: err.message });
  }
});

export default router;

import { Router } from 'express';
import { db } from '../db';
import { readLocalRules, writeLocalRules } from '../localFallback';

const router = Router();

function mapRulesRow(r: any) {
  return {
    perShowUpHigh: parseFloat(r.per_show_up_high ?? 350),
    perShowUpLow:  parseFloat(r.per_show_up_low  ?? 200),
    perPoHigh:     parseFloat(r.per_po_high      ?? 150),
    perPoLow:      parseFloat(r.per_po_low       ?? 100),
    hourlyRate:    parseFloat(r.hourly_rate       ?? 85),
    poThreshold:   parseInt(r.po_threshold        ?? 140),
  };
}

// GET /api/rules
router.get('/', async (_req, res) => {
  if (db.pool && db.isConnected) {
    try {
      const result = await db.pool.query(
        "SELECT * FROM commission_rules WHERE id = 'default'"
      );
      if (result.rows.length > 0) {
        return res.json(mapRulesRow(result.rows[0]));
      }
    } catch (err) {
      console.error('[Rules] DB read error:', err);
    }
  }
  return res.json(readLocalRules());
});

// POST /api/rules
router.post('/', async (req, res) => {
  const { perShowUpHigh, perShowUpLow, perPoHigh, perPoLow, hourlyRate, poThreshold } = req.body;

  if (db.pool && db.isConnected) {
    try {
      await db.pool.query(`
        INSERT INTO commission_rules
          (id, base_salary, per_booking, per_deposit_collected, per_show_up,
           target_bookings, bonus_amount,
           per_show_up_high, per_show_up_low, per_po_high, per_po_low, hourly_rate, po_threshold)
        VALUES ('default', 0, 0, 0, 0, 0, 0, $1, $2, $3, $4, $5, $6)
        ON CONFLICT (id) DO UPDATE SET
          per_show_up_high = EXCLUDED.per_show_up_high,
          per_show_up_low  = EXCLUDED.per_show_up_low,
          per_po_high      = EXCLUDED.per_po_high,
          per_po_low       = EXCLUDED.per_po_low,
          hourly_rate      = EXCLUDED.hourly_rate,
          po_threshold     = EXCLUDED.po_threshold,
          updated_at       = CURRENT_TIMESTAMP
      `, [perShowUpHigh, perShowUpLow, perPoHigh, perPoLow, hourlyRate, poThreshold]);
      return res.json({ success: true });
    } catch (err: any) {
      return res.status(500).json({ error: 'Database write error: ' + err.message });
    }
  }
  writeLocalRules({ perShowUpHigh, perShowUpLow, perPoHigh, perPoLow, hourlyRate, poThreshold });
  res.json({ success: true });
});

export default router;

