export type LeadStatus = 'booked' | 'rescheduled' | 'cancelled' | 'showed_up' | 'no_show';

export interface LeadReport {
  id?: string;
  managerName: string;
  clientName: string;
  clientPhone?: string;
  amocrmLeadId?: string;
  bookingDate: string;
  status: LeadStatus;
  city?: string;
  depositRequired: boolean;
  depositAmount: number;
  depositPaid: boolean;
  visitCost?: number;
  comments?: string;
  createdAt?: string;
  updatedAt?: string;
}

export interface CommissionRules {
  perShowUpHigh: number;  // ставка за визит при ПО > порога
  perShowUpLow:  number;  // ставка за визит при ПО ≤ порога
  perPoHigh:     number;  // ставка за запись при ПО > порога
  perPoLow:      number;  // ставка за запись при ПО ≤ порога
  hourlyRate:    number;  // ставка за час работы
  poThreshold:   number;  // порог ПО для смены ставок
}

export interface DbStatus {
  provider: 'local' | 'postgres';
  configured: boolean;
  error?: string;
  connectionInfo?: string;
  tableName: string;
  geminiActive: boolean;
}

export interface StaffMember {
  name: string;
  role: 'admin' | 'manager';
  pin: string;
  department: string;
  avatarColor: string;
  status: 'online' | 'offline';
  lastActive: string;
  bio: string;
}

export interface ShiftSession {
  id: number;
  managerName: string;
  startedAt: string;
  endedAt: string | null;
  breakStartedAt: string | null;
  totalBreakSecs: number;
}

export interface ManagerPerformance {
  managerName: string;
  totalBookings: number;
  totalDeposits: number;
  totalShowUps: number;
  totalNoShows: number;
  workedSeconds: number;
  earnedSalary: number;
  leads: LeadReport[];
}

import type { LeadReport, CommissionRules, StaffMember, ShiftSession } from '../types';

export class ApiError extends Error {
  constructor(public status: number, message: string) {
    super(message);
    this.name = 'ApiError';
  }
}

async function request<T>(url: string, options?: RequestInit): Promise<T> {
  const res = await fetch(url, {
    headers: { 'Content-Type': 'application/json', ...options?.headers },
    ...options,
  });
  if (!res.ok) {
    let message = res.statusText;
    try { message = (await res.json()).error || message; } catch { /* ignore */ }
    throw new ApiError(res.status, message);
  }
  return res.json() as Promise<T>;
}

export const api = {
  leads: {
    list: () =>
      request<LeadReport[]>('/api/leads'),
    save: (lead: LeadReport) =>
      request<{ id: string; success: boolean }>('/api/leads', { method: 'POST', body: JSON.stringify(lead) }),
    delete: (id: string) =>
      request<{ success: boolean }>(`/api/leads/${id}`, { method: 'DELETE' }),
  },

  rules: {
    get: () =>
      request<CommissionRules>('/api/rules'),
    save: (rules: CommissionRules) =>
      request<{ success: boolean }>('/api/rules', { method: 'POST', body: JSON.stringify(rules) }),
  },

  users: {
    list: () =>
      request<StaffMember[]>('/api/users'),
    save: (user: Partial<StaffMember> & { name: string }) =>
      request<{ success: boolean }>('/api/users', { method: 'POST', body: JSON.stringify(user) }),
    delete: (name: string) =>
      request<{ success: boolean }>(`/api/users/${encodeURIComponent(name)}`, { method: 'DELETE' }),
  },

  auth: {
    login: (pin: string, name?: string) =>
      request<{ success: boolean; user: StaffMember }>('/api/auth/login', {
        method: 'POST', body: JSON.stringify({ pin, ...(name ? { name } : {}) }),
      }),
    logout: (name: string) =>
      request<{ success: boolean }>('/api/auth/logout', { method: 'POST', body: JSON.stringify({ name }) }),
    heartbeat: (name: string) =>
      request<{ success: boolean }>('/api/auth/heartbeat', { method: 'POST', body: JSON.stringify({ name }) }),
  },

  shifts: {
    active: (name: string) =>
      request<{ active: boolean; session: ShiftSession | null }>(`/api/shifts/active?name=${encodeURIComponent(name)}`),
    start: (name: string) =>
      request<{ success: boolean; session: ShiftSession | null }>('/api/shifts/start', { method: 'POST', body: JSON.stringify({ name }) }),
    end: (name: string) =>
      request<{ success: boolean; workedSeconds: number }>('/api/shifts/end', { method: 'POST', body: JSON.stringify({ name }) }),
    breakStart: (name: string) =>
      request<{ success: boolean }>('/api/shifts/break/start', { method: 'POST', body: JSON.stringify({ name }) }),
    breakEnd: (name: string) =>
      request<{ success: boolean }>('/api/shifts/break/end', { method: 'POST', body: JSON.stringify({ name }) }),
    monthly: (name: string, year: number, month: number) =>
      request<{ totalSeconds: number }>(`/api/shifts/monthly?name=${encodeURIComponent(name)}&year=${year}&month=${month}`),
    monthlyAll: (year: number, month: number) =>
      request<Record<string, number>>(`/api/shifts/monthly-all?year=${year}&month=${month}`),
  },
};

import { useState, useCallback } from 'react';
import { api } from '../api/client';
import type { LeadReport, CommissionRules, StaffMember } from '../types';

const INITIAL_RULES: CommissionRules = {
  perShowUpHigh: 350,
  perShowUpLow:  200,
  perPoHigh:     150,
  perPoLow:      100,
  hourlyRate:    85,
  poThreshold:   140,
};

export function useData() {
  const [leads, setLeads] = useState<LeadReport[]>([]);
  const [rules, setRules] = useState<CommissionRules>(INITIAL_RULES);
  const [allUsers, setAllUsers] = useState<StaffMember[]>([]);
  const [loading, setLoading] = useState(true);

  const refreshLeads = useCallback(async () => {
    try { setLeads(await api.leads.list()); } catch (e) { console.error('[Data] Failed to fetch leads:', e); }
  }, []);

  const refreshRules = useCallback(async () => {
    try { setRules(await api.rules.get()); } catch (e) { console.error('[Data] Failed to fetch rules:', e); }
  }, []);

  const refreshUsers = useCallback(async () => {
    try { setAllUsers(await api.users.list()); } catch (e) { console.error('[Data] Failed to fetch users:', e); }
  }, []);

  const initialize = useCallback(async () => {
    setLoading(true);
    await Promise.all([refreshLeads(), refreshRules(), refreshUsers()]);
    setLoading(false);
  }, [refreshLeads, refreshRules, refreshUsers]);

  return { leads, rules, allUsers, loading, refreshLeads, refreshRules, refreshUsers, initialize };
}

