function calcSalary(
  showUps: number,
  totalBookings: number,
  workedSecs: number,
  rules: CommissionRules
): number {
  const overThreshold = totalBookings > rules.poThreshold;
  const visitRate = overThreshold ? rules.perShowUpHigh : rules.perShowUpLow;
  const poRate    = overThreshold ? rules.perPoHigh     : rules.perPoLow;
  const hours     = workedSecs / 3600;
  return showUps * visitRate + hours * rules.hourlyRate + totalBookings * poRate;
}

